export const meta = {
  name: 'serverless-plugins-intel',
  description: 'Step 1: deep read-only analysis of CoorpAcademy/serverless-plugins, then author foundational repo docs',
  phases: [
    { title: 'Analyze', detail: '6 parallel analysts deep-read the repo (read-only)' },
    { title: 'Document', detail: '4 doc-writers produce grounded docs/ files' },
  ],
}

const REPO = '/Users/silouane/coorp/serverless-plugins'

const FINDING_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    domain: { type: 'string' },
    summary: { type: 'string', description: 'one-paragraph executive summary' },
    markdown: { type: 'string', description: 'rich, grounded markdown section with file:line references' },
    gotchas: { type: 'array', items: { type: 'string' } },
    fileRefs: { type: 'array', items: { type: 'string' } },
  },
  required: ['domain', 'summary', 'markdown', 'gotchas'],
}

const DOC_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    path: { type: 'string' },
    summary: { type: 'string' },
    lineCount: { type: 'number' },
  },
  required: ['path', 'summary'],
}

const common = `You are analyzing the repo at ${REPO} (a lerna + yarn-workspaces monorepo of Serverless Framework plugins). READ-ONLY: do NOT write, edit, or run mutating commands. Ground every claim in actual file contents with path:line references. Be exhaustive and precise — this feeds permanent engineering docs and a Claude Code skill/agent. Packages: packages/serverless-offline-{s3,sqs,kinesis,dynamodb-streams}, packages/dynamodb-streams-readable, packages/serverless-apigateway-access-logs.`

const ANALYSTS = [
  {
    label: 'arch-lifecycle',
    domain: 'Architecture & plugin lifecycle',
    prompt: `${common}
Focus: the shared architecture of the 4 serverless-offline-* plugins. Read all four src/index.js files. Document:
- The plugin class shape, the constructor signature, and the v4 logger 3rd-arg contract.
- The hooks map (offline:start:init / ready / offline:start / offline:start:end) and the exact lifecycle: start() -> _mergeOptions -> _getEvents -> _createLambda -> _create{S3,Sqs,Kinesis,DynamodbStreams} -> ready/_listenForTermination -> end().
- How the Lambda runner is loaded (dynamic import('serverless-offline/lambda')) and why.
- _mergeOptions option precedence (defaultOptions, provider, offline opts, custom opts, cliOptions).
- _getEvents / _resolveFn event extraction and ARN/Fn::GetAtt resolution.
- The graceful-shutdown / process.exit and NODE_ENV==='test' guards.
Return a thorough markdown architecture section plus gotchas (e.g. redundant this.x=null then this.x=value init, process.exit usage, the dead @serverless/utils/log import).`,
  },
  {
    label: 'package-internals',
    domain: 'Per-package internals & differences',
    prompt: `${common}
Focus: the emulator sub-modules and event classes. Read: s3.js, sqs.js, kinesis.js, dynamodb-streams.js, every *-event.js and *-event-definition.js, plus packages/dynamodb-streams-readable/src/index.js (+ its test/index.js) and packages/serverless-apigateway-access-logs/src/index.js. Document for EACH package: what emulator/client it uses (Minio, aws-sdk SQSClient, kinesalite, dynamodb), how it waits for resources, how it listens/polls, how it maps native events into the AWS Lambda event shape, batch/queue handling (p-queue in sqs), and the autoCreate path (sqs). Call out per-package differences and the two non-offline utility packages. Return a thorough markdown section + gotchas (e.g. the dead s3.js _s3Event method, this.region bug in sqs.js).`,
  },
  {
    label: 'conventions',
    domain: 'Code conventions & style',
    prompt: `${common}
Focus: coding conventions. Read .eslintrc.js, .eslintignore, and sample broadly across src files. Document: lodash/fp usage and style, the FP-with-classes mix (fp/no-class off), immutability patterns and where they're violated, error-handling patterns (try/catch + log.warning), naming conventions, the prettier config via @coorpacademy/coorpacademy/prettier, the no-shadow allow:['toString'] and other notable rule overrides, node es-syntax >=16 with dynamicImport ignore. Produce a concrete 'how to write code in this repo' convention guide with do/don't examples drawn from real code. Return markdown + gotchas.`,
  },
  {
    label: 'testing-ci',
    domain: 'Testing, CI & local dev',
    prompt: `${common}
Focus: the test and CI story. Read ava.config.js, .nycrc, .travis.yml, docker-compose.yml, docker-compose.test.yml, scripts/*.sh, and all of tests/serverless-plugins-integration/ (utils.js, test-*.js, the serverless.*.yml, custom.yml, lambda/handler.js and handler.py, package.json). Document: that ava only globs packages/**/test/*.js so ONLY dynamodb-streams-readable has unit tests and the offline plugins have NONE; the integration harness (spawn sls offline, detect lambda invocations via stderr 'Billed Duration' regex, kill on count); the docker services (minio/elasticmq/kinesalite/dynamodb-local) and create-*.sh seeding; the root npm scripts (eslint, nyc ava, test:integration via lerna). Explicitly map what is runnable WITHOUT docker (eslint, ava on the readable pkg) vs WITH docker, and what additionally needs serverless v4 + SERVERLESS_ACCESS_KEY. Return markdown + gotchas.`,
  },
  {
    label: 'deps-publish',
    domain: 'Dependencies, versioning & publishing',
    prompt: `${common}
Focus: dependency graph, versioning and publishing. Read root package.json, lerna.json, every packages/*/package.json, .nvmrc. Document: lerna independent versioning + workspaces + hoist + --no-package-lock bootstrap; current versions of each package; the serverless / serverless-offline peer coupling (offline-* peer 'serverless-offline ^10.0.2 || >=11'; root deps serverless ^3.36); the serverless-offline<->serverless major coupling (offline13->sls3, offline14->sls4); node engines >=18 / .nvmrc; aws-sdk v2 usage; the publish flow (lerna publish, 'New release :zap:' message). Give a concrete recommended versioning/peer strategy for the v4 migration that PRESERVES v3 compatibility (wide peers, possibly minor bumps). Return markdown + gotchas.`,
  },
  {
    label: 'v4-and-prs',
    domain: 'v4 migration mechanics & open-PR re-verification',
    prompt: `${common}
Focus: the serverless v4 break and the open PRs. The break: v4 removed @serverless/utils/log (top-level require throws on every command) and removed serverless.cli.log; v4 injects {log, writeText, progress} as the plugin constructor's 3rd arg (this also exists since serverless v3.0, so the fix is backward compatible). Re-verify, against CURRENT master source, each of these open PRs and state for each: does the patch still apply to current code, is the underlying issue still present, and is the IDEA worth re-implementing? PRs: #166 (this.region -> this.options.region in sqs.js), #253 (distinct delete-batch IDs), #249 (await kinesis lambda.create + a bad serverless-offline/src/lambda import), #211 (queueName override from config), #98 (dynamodb 'table has no streams' error), #100 (dynamodb retries option), #168 (start lambdas without SQS events / default host localhost), #183 (autocreate DLQ from RedrivePolicy), #99 (log function errors), #117 (enabled flag), #137 (avoid waiting for termination). Note which target a now-removed architecture (functionHelper.createHandler/LambdaContext/before:offline:start hooks/this.service). Also confirm the 5 dependabot PRs are mooted by a lockfile regen. Read the relevant current src files to verify. Return markdown table (PR -> applies? / issue present? / verdict) + gotchas.`,
  },
]

phase('Analyze')
const findings = (await parallel(
  ANALYSTS.map(a => () => agent(a.prompt, { schema: FINDING_SCHEMA, phase: 'Analyze', label: a.label }))
)).filter(Boolean)

const pooled = findings.map(f => `# ${f.domain}\n\n${f.markdown}\n\nGOTCHAS:\n${(f.gotchas||[]).map(g => '- ' + g).join('\n')}`).join('\n\n---\n\n')
log(`Collected ${findings.length}/6 analyst findings; writing docs`) 

const WRITERS = [
  {
    label: 'doc:architecture',
    path: 'docs/architecture.md',
    brief: `Write ${REPO}/docs/architecture.md: a definitive architecture guide for the repo. Cover the monorepo layout, the shared 4-plugin lifecycle/hooks pattern, the Lambda-runner dynamic import, option merging, event extraction & ARN resolution, the emulator sub-modules per package, and the two utility packages. Use real file:line references. Include a lifecycle diagram (ascii) and a per-package quick-reference table.`,
  },
  {
    label: 'doc:conventions',
    path: 'docs/conventions.md',
    brief: `Write ${REPO}/docs/conventions.md: the coding conventions / style guide. lodash/fp usage, FP-with-classes, immutability, error handling, naming, eslint+prettier rules that matter, node syntax constraints. Concrete do/don't examples from the actual code. End with a 'checklist before commit' (eslint, no dead @serverless/utils/log import, etc.).`,
  },
  {
    label: 'doc:testing-ci',
    path: 'docs/testing-and-ci.md',
    brief: `Write ${REPO}/docs/testing-and-ci.md: the testing & CI guide. Explain ava config + the unit-test GAP (offline plugins have none), the docker integration harness and how it detects lambda calls, the docker-compose services + seed scripts, the travis matrix, and a clear table of "what can I run and what does it need" (eslint = nothing; ava = nothing/just node; integration = docker; v4 e2e = docker+serverless@4+SERVERLESS_ACCESS_KEY). Recommend adding docker-free unit tests for pure logic and sketch what to test.`,
  },
  {
    label: 'doc:publishing',
    path: 'docs/publishing-and-versioning.md',
    brief: `Write ${REPO}/docs/publishing-and-versioning.md: versioning, dependency coupling, and publish guide. lerna independent versioning, workspaces/hoist, current package versions, the serverless<->serverless-offline major coupling, node engines, and the RECOMMENDED v4 migration version/peer strategy that preserves v3 (wide peers, canary-first publish). Include the exact publish commands.`,
  },
]

phase('Document')
const docs = (await parallel(
  WRITERS.map(w => () => agent(
    `${common}\nUsing ONLY these analyst findings as source-of-truth (re-read files to confirm specifics as needed):\n\n${pooled}\n\nTASK: ${w.brief}\nWrite the file to disk now with the Write tool. Make it thorough, accurate, skimmable, and well-structured with headings and tables. Return the path, a one-line summary, and the line count.`,
    { schema: DOC_SCHEMA, phase: 'Document', label: w.label }
  ))
)).filter(Boolean)

return {
  analystCount: findings.length,
  docsWritten: docs,
  intelligence: findings.map(f => ({ domain: f.domain, summary: f.summary, gotchas: f.gotchas })),
  prVerificationDomain: (findings.find(f => /open-PR|PR re/i.test(f.domain)) || {}).markdown || 'see v4-and-prs finding',
  fullPooledForAuthoring: pooled,
}

