export const meta = {
  name: 'serverless-v4-review',
  description: 'Step 6: adversarial multi-lens review of the staged v4 diff, then independently verify each finding',
  phases: [
    { title: 'Review', detail: '6 parallel lenses hunt for bugs/regressions in the staged diff' },
    { title: 'Verify', detail: 'each finding independently verified before it counts' },
  ],
}

const REPO = '/Users/silouane/coorp/serverless-plugins'

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          title: { type: 'string' },
          file: { type: 'string' },
          severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'nit'] },
          detail: { type: 'string' },
          recommendation: { type: 'string' },
        },
        required: ['title', 'severity', 'detail', 'recommendation'],
      },
    },
  },
  required: ['findings'],
}

const VERDICT_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    real: { type: 'boolean' },
    severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'nit'] },
    rationale: { type: 'string' },
    fix: { type: 'string' },
  },
  required: ['real', 'rationale'],
}

const ctx = `Repo: ${REPO}. Branch feat/serverless-v4-support. The changes are STAGED (not committed) vs master — view them with \`cd ${REPO} && git --no-pager diff --cached -- packages/\` (new files like src/log.js and test/index.js appear there since they're staged). You may also Read any file directly.

Background: this PR migrates the 4 serverless-offline-* plugins to Serverless Framework v4 (remove \`@serverless/utils/log\`, take \`{log}\` from the 3rd constructor arg via \`src/log.js\` normalizeLog, replace \`serverless.cli.log\`→\`this.log.notice\`), and re-implements community-PR ideas: #166 (this.region→this.options.region in sqs/kinesis/ddb), #253 (unique SQS delete-batch Ids), #211 (SQS queueName override), #98 (ddb clear no-streams error), #100 (kinesis bounded+logged retry), #249 (kinesis await create). It must stay BACKWARD-COMPATIBLE with serverless v3. Acceptance criteria are in ${REPO}/docs/plans/. Be concrete and skeptical; cite file:line. If you find nothing in your lens, return an empty findings array.`

const LENSES = [
  { label: 'lens:v4-logger', prompt: `${ctx}\nLENS = v4/v3 logger correctness. Verify: zero \`@serverless/utils/log\` and zero \`serverless.cli.log\` remain; the logger is taken from the 3rd ctor arg and threaded into every emulator sub-module; every \`this.log.<level>\` call uses a level that EXISTS in the normalizeLog shim (debug/info/notice/warning/error/success); no call site can throw if \`log\` is undefined (v3 path); normalizeLog is imported correctly in each file. Flag any missed cli.log/log.debug/log.warn, any level mismatch, or any place still reading a module-level \`log\`.` },
  { label: 'lens:features', prompt: `${ctx}\nLENS = correctness of the re-implemented features. For EACH: #166 — does the EMITTED event actually carry the right awsRegion now (check sqs.js/kinesis.js/dynamodb-streams.js event construction)? #253 — are delete-batch entry Ids unique within a batch AND ≤80 chars AND do ReceiptHandles still line up with the right message? #211 — is queueName override non-mutating and does it actually take effect in the create path (not just the helper)? #98 — is the no-streams error thrown BEFORE the cryptic failure, with the table name? #100 — is the kinesis retry actually bounded now (no infinite loop) and are failures logged? #249 — is create awaited? Flag any feature that is only half-wired (e.g. a pure helper added but not called from the real code path).` },
  { label: 'lens:regression', prompt: `${ctx}\nLENS = regressions / behavior changes. The migration removed dead code, the declare-null idiom (in index.js), and renamed a class (DynamodbStreamsEvent). Verify nothing real broke: hooks map unchanged; lifecycle (start/ready/end) intact; process.exit still guarded by skipExit/NODE_ENV; option-merge precedence unchanged; the renamed ddb event class is still exported/constructed correctly; the kinesis-event-definition omit change (tableName→streamName) doesn't drop a real field; deleting s3 _create/_s3Event didn't remove something still referenced; removing the \`./s3-event-definition\` require didn't break anything still using it. Flag any actual breakage.` },
  { label: 'lens:tests', prompt: `${ctx}\nLENS = test adequacy. Read each packages/*/test/index.js. Are the assertions real (not tautological)? Do the #166/#253/#211/#98/#100 regression-guard tests actually fail if the bug were reintroduced? Any test that constructs an emulator class that builds an AWS/Minio client (should be avoided/docker-free)? Any missing critical case (e.g. delete-batch uniqueness when MessageIds collide; normalizeLog null-safety; awsRegion value)? Flag weak/tautological/over-mocked tests and meaningful coverage gaps.` },
  { label: 'lens:conventions', prompt: `${ctx}\nLENS = conventions & cross-package consistency. lodash/fp style preserved; no accidental input mutation; naming consistent; the 4 src/log.js are byte-identical; the v4 migration was applied uniformly across all 4 packages (same constructor shape, same threading); no leftover \`eslint-disable\` directives; no stray debug noise. Flag inconsistencies between packages and any deviation from docs/conventions.md that isn't justified by a plan doc.` },
  { label: 'lens:packaging', prompt: `${ctx}\nLENS = packaging & semver. For each touched package.json: is \`src/log.js\` added to \`files\`? Is the version bumped (minor)? Is the peer range kept WIDE (\`^10.0.2 || >=11\`, NOT narrowed to v14+)? Is the README updated with the v4 note? Are there any NEW runtime deps added (there should be none — #253 must NOT add uuid)? Flag missing files[] entries, wrong/narrowed peers, missing bumps, or accidental dependency additions.` },
]

phase('Review')
const lensResults = (await parallel(
  LENSES.map(l => () => agent(l.prompt, { schema: FINDINGS_SCHEMA, phase: 'Review', label: l.label }))
)).filter(Boolean)

const all = lensResults.flatMap(r => r.findings || [])
const seen = new Set()
const deduped = all.filter(f => {
  const k = `${f.file || ''}|${f.title}`
  if (seen.has(k)) return false
  seen.add(k)
  return true
})
log(`${all.length} raw findings; ${deduped.length} after dedup; verifying each`)

phase('Verify')
const verified = (await parallel(
  deduped.map(f => () =>
    agent(
      `${ctx}\nIndependently VERIFY this review finding against the actual code. Do NOT trust it — confirm or refute by reading the relevant file(s).\n\nFINDING (${f.severity}) in ${f.file || '?'}: ${f.title}\nDETAIL: ${f.detail}\nPROPOSED FIX: ${f.recommendation || ''}\n\nReturn real=true ONLY if it is a genuine issue worth fixing in this PR; default real=false if uncertain, cosmetic, or already handled. If real, give the concrete minimal fix and the accurate severity.`,
      { schema: VERDICT_SCHEMA, phase: 'Verify', label: (f.file || 'finding').split('/').pop() }
    ).then(v => ({ ...f, verdict: v }))
  )
)).filter(Boolean)

const confirmed = verified.filter(v => v.verdict && v.verdict.real)
return {
  rawFindings: all.length,
  deduped: deduped.length,
  confirmedCount: confirmed.length,
  confirmed: confirmed.map(c => ({ title: c.title, file: c.file, severity: c.verdict.severity || c.severity, fix: c.verdict.fix, rationale: c.verdict.rationale })),
  refuted: verified.filter(v => !(v.verdict && v.verdict.real)).map(v => ({ title: v.title, why: v.verdict && v.verdict.rationale })),
}

